import { access, constants, stat } from "node:fs/promises";
import path from "node:path";
import { promisify } from "node:util";

const execFileAsync = promisify(execFile);

const INDEX_DB_NAME = ".fg-index.db";

export interface IndexStatus {
  isProjectRoot: boolean;
  projectRoot: string | null;
  dbExists: boolean;
  needsUpdate: boolean;
  reason: string;
}

export interface TriggerResult {
  triggered: boolean;
  pid?: number;
  error?: string;
  status: IndexStatus;
}

export async function findProjectRoot(startPath: string): Promise<string | null> {
  let current = path.resolve(startPath);

  for (let i = 0; i < 50; i++) {
    try {
      await access(path.join(current, ".git"), constants.F_OK);
      return current;
    } catch {
      const parent = path.dirname(current);
      if (parent === current) return null;
      current = parent;
    }
  }

  return null;
}

async function getNewestSourceMtime(projectRoot: string): Promise<number> {
  const extensions = [".ts", ".tsx", ".go"];
  let newest = 0;

  async function walk(dir: string): Promise<void> {
    try {
      const { readdir } = await import("node:fs/promises");
      const entries = await readdir(dir, { withFileTypes: true });
      for (const entry of entries) {
        const name = entry.name;
        if (name.startsWith(".") || name === "node_modules" || name === "vendor" || name === "dist" || name === "out") continue;
        const fullPath = path.join(dir, name);
        if (entry.isDirectory()) {
          await walk(fullPath);
        } else if (entry.isFile()) {
          const ext = path.extname(name);
          if (extensions.includes(ext)) {
            try {
              const s = await stat(fullPath);
              if (s.mtimeMs > newest) newest = s.mtimeMs;
            } catch {
              continue;
            }
          }
        }
      }
    } catch {
      return;
    }
  }

  await walk(projectRoot);
  return newest;
}

export async function checkIndexStatus(projectDir: string): Promise<IndexStatus> {
  const projectRoot = await findProjectRoot(projectDir);

  if (!projectRoot) {
    return {
      isProjectRoot: false,
      projectRoot: null,
      dbExists: false,
      needsUpdate: false,
      reason: "not inside a git repository",
    };
  }

  const dbPath = path.join(projectRoot, INDEX_DB_NAME);

  let dbExists = false;
  let dbMtime = 0;
  try {
    const s = await stat(dbPath);
    dbExists = true;
    dbMtime = s.mtimeMs;
  } catch {
    // db does not exist
  }

  if (!dbExists) {
    return {
      isProjectRoot: true,
      projectRoot,
      dbExists: false,
      needsUpdate: true,
      reason: "no existing index database",
    };
  }

  const newestSource = await getNewestSourceMtime(projectRoot);

  if (newestSource > dbMtime) {
    return {
      isProjectRoot: true,
      projectRoot,
      dbExists: true,
      needsUpdate: true,
      reason: "source files modified after last index build",
    };
  }

  return {
    isProjectRoot: true,
    projectRoot,
    dbExists: true,
    needsUpdate: false,
    reason: "index is up to date",
  };
}

export async function triggerIncrementalIndex(projectRoot: string): Promise<TriggerResult> {
  const status = await checkIndexStatus(projectRoot);

  if (!status.needsUpdate || !status.projectRoot) {
    return { triggered: false, status };
  }

  try {
    const child = execFile(
      "npx",
      ["ts-node", "src/cli/fg-index.ts", "--project-dir", status.projectRoot],
      {
        cwd: status.projectRoot,
        detached: true,
        stdio: "ignore",
      },
      (err) => {
        if (err) {
          process.stderr.write(`[mindkeeper] fg-index failed: ${err.message}\n`);
        }
      }
    );

    child.unref();

    return { triggered: true, pid: child.pid, status };
  } catch (err: unknown) {
    const message = err instanceof Error ? err.message : String(err);
    return { triggered: false, error: message, status };
  }
}

export async function onSessionStart(startPath?: string): Promise<TriggerResult> {
  const cwd = startPath ?? process.cwd();
  return triggerIncrementalIndex(cwd);
}
